  }

  const id = Number(rawId);
  return Number.isInteger(id) && id > 0 ? id : null;
};

const readRequiredString = (value: unknown): string | null => {
  if (typeof value !== "string") {
    return null;
  }

  const trimmed = value.trim();
  return trimmed.length > 0 ? trimmed : null;
};

const readEmail = (value: unknown): string | null => {
  const email = readRequiredString(value)?.toLowerCase();
  if (!email) {
    return null;
  }

  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email) ? email : null;
};

const readPassword = (value: unknown): string | null => {
  if (typeof value !== "string" || value.length < 8) {
    return null;
  }

  return value;
};

const readUrl = (value: unknown): string | null => {
  const rawUrl = readRequiredString(value);
  if (!rawUrl) {
    return null;
  }

  try {
    new URL(rawUrl);
    return rawUrl;
  } catch {
    return null;
  }
};

const readOptionalDescription = (value: unknown): string | null => {
  if (value === undefined || value === null) {
    return null;
  }

  return typeof value === "string" ? value : String(value);
};

const readOptionalFolderId = (value: unknown): number | null | undefined => {
  if (value === undefined) {
    return undefined;
  }

  if (value === null) {
    return null;
  }

  const folderId = typeof value === "number" ? value : Number(value);
  return Number.isInteger(folderId) && folderId > 0 ? folderId : undefined;
};

const resolveFolderId = (
  value: unknown,
  userId: number,
): { ok: true; folderId: number | null } | { ok: false } => {
  const folderId = readOptionalFolderId(value);

  if (folderId === undefined) {
    return { ok: false };
  }

  if (folderId !== null && !getFolderById(folderId, userId)) {
    return { ok: false };
  }

  return { ok: true, folderId };
};

const requireAuth = (req: Request, res: Response, next: NextFunction) => {
  const authorization = req.header("authorization");
  if (!authorization?.startsWith("Bearer ")) {
    return res.status(401).json({ error: "missing or invalid token" });
  }

  const token = authorization.slice("Bearer ".length).trim();
  try {
    const payload = jwt.verify(token, JWT_SECRET) as Partial<JwtPayload>;
    const userId = payload.userId;
    if (typeof userId !== "number" || !Number.isInteger(userId) || !getUserById(userId)) {
      return res.status(401).json({ error: "missing or invalid token" });
    }

    res.locals.userId = userId;
    return next();
  } catch {
    return res.status(401).json({ error: "missing or invalid token" });
  }
};

const getAuthenticatedUserId = (res: Response): number => Number(res.locals.userId);

